public void testNextLongWithQuotedValue() throws IOException {
    JsonReader reader = new JsonReader(reader("[\"123\"]"));
    reader.beginArray();
    assertEquals(123L, reader.nextLong());
    reader.endArray();
  }

public void testNextIntWithQuotedValue() throws IOException {
    JsonReader reader = new JsonReader(reader("[\"456\"]"));
    reader.beginArray();
    assertEquals(456, reader.nextInt());
    reader.endArray();
  }

public void testNextLongWithSingleQuotedValue() throws IOException {
    JsonReader reader = new JsonReader(reader("['789']"));
    reader.setLenient(true);
    reader.beginArray();
    assertEquals(789L, reader.nextLong());
    reader.endArray();
  }

